// ============================================================================
// PM CENTRAL BRAIN - ROUTE DISPATCHER V4.4
// ============================================================================

const input = $input.first().json;
const body = input.body || input;

const action = body.action || 'quick_action';

const context = {
  action: action,
  session_id: body.session_id || `session_${Date.now()}`,
  timestamp: new Date().toISOString(),

  genesis_data: action === 'genesis' ? {
    scope: body.scope,
    answers: body.answers,
    project_name: body.project_name,
    deadline: body.deadline,
    context_data: body.context_data || {}
  } : null,

  task_data: action === 'task_launch' ? {
    task_id: body.task_id,
    project_id: body.project_id || body.shared_memory?.project_id,
    user_message: body.chatInput || body.message,
    active_agent_id: body.activeAgentId || 'orchestrator',
    shared_memory: body.shared_memory || {},
    task_context: body.task_context || {}
  } : null,

  chat_data: action === 'quick_action' || action === 'chat' ? {
    message: body.chatInput || body.message,
    project_id: body.project_id || body.shared_memory?.project_id,
    active_agent_id: body.activeAgentId || 'orchestrator',
    image: body.image,
    shared_memory: body.shared_memory || {},
    task_context: body.task_context || {}
  } : null,

  writeback_data: action === 'write_back' ? {
    task_id: body.task_id,
    project_id: body.project_id,
    updates: body.updates,
    deliverable_url: body.deliverable_url,
    state_flags: body.state_flags
  } : null
};

return [{ json: context }];

// ============================================================================
// GENESIS HANDLER - Create Project + Tasks
// ============================================================================

const TASK_TEMPLATES = {
  meta_ads: [
    { title: 'Setup Technique & Budget CBO', description: 'Configurer la structure de campagne Meta', assignee: 'marcus', phase: 'Setup', estimated_hours: 2, context_questions: ['Budget quotidien ?', 'ROAS cible ?'], depends_on: [] },
    { title: 'Setup Tracking (Pixel/CAPI)', description: 'Installer Pixel Meta + CAPI', assignee: 'sora', phase: 'Setup', estimated_hours: 3, context_questions: ['GTM installé ?', 'Events à tracker ?'], depends_on: [] },
    { title: 'Copywriting Ads (3 variations)', description: 'Rédiger 3 variations de textes', assignee: 'milo', phase: 'Production', estimated_hours: 3, context_questions: ['Ton de la marque ?', 'Offre principale ?'], depends_on: ['Setup Tracking (Pixel/CAPI)'] },
    { title: 'Génération Visuels Meta', description: 'Créer les visuels avec IA', assignee: 'milo', phase: 'Production', estimated_hours: 4, context_questions: ['Format préféré ?', 'Éléments de marque ?'], depends_on: ['Setup Tracking (Pixel/CAPI)'] }
  ],
  seo: [
    { title: 'Audit Sémantique & Technique', description: 'Analyser structure SEO', assignee: 'luna', phase: 'Audit', estimated_hours: 5, context_questions: ['URL du site ?', 'Concurrents ?'], depends_on: [] },
    { title: 'Recherche Keywords', description: 'Identifier mots-clés potentiel', assignee: 'luna', phase: 'Audit', estimated_hours: 3, context_questions: ['Thématiques ?', 'Zone géo ?'], depends_on: ['Audit Sémantique & Technique'] },
    { title: 'Configuration GSC & GA4', description: 'Connecter Search Console', assignee: 'sora', phase: 'Setup', estimated_hours: 1, context_questions: ['Accès GSC ?'], depends_on: [] },
    { title: 'Rédaction Page Pilier', description: 'Rédiger contenu SEO', assignee: 'milo', phase: 'Production', estimated_hours: 4, context_questions: ['Sujet ?', 'Longueur ?'], depends_on: ['Recherche Keywords'] }
  ],
  sem: [
    { title: 'Audit Compte Google Ads', description: 'Analyser performance actuelle', assignee: 'sora', phase: 'Audit', estimated_hours: 2, context_questions: ['Accès Google Ads ?'], depends_on: [] },
    { title: 'Setup Campagne Search', description: 'Créer campagne Google Search', assignee: 'marcus', phase: 'Setup', estimated_hours: 3, context_questions: ['Budget ?', 'Zones géo ?'], depends_on: ['Audit Compte Google Ads'] },
    { title: 'Copywriting RSA', description: 'Rédiger titres et descriptions', assignee: 'milo', phase: 'Production', estimated_hours: 2, context_questions: ['USP ?'], depends_on: [] }
  ],
  analytics: [
    { title: 'Plan de Taggage GA4 + GTM', description: 'Définir plan de taggage', assignee: 'sora', phase: 'Setup', estimated_hours: 4, context_questions: ['Events clés ?'], depends_on: [] },
    { title: 'Debugging Data Layer', description: 'Vérifier anomalies', assignee: 'sora', phase: 'Audit', estimated_hours: 2, context_questions: ['Anomalies ?'], depends_on: ['Plan de Taggage GA4 + GTM'] },
    { title: 'Création Dashboard', description: 'Construire tableau de bord', assignee: 'sora', phase: 'Production', estimated_hours: 3, context_questions: ['KPIs ?'], depends_on: ['Debugging Data Layer'] }
  ]
};

function calculateDueDates(tasks, deadline) {
  const phases = ['Audit', 'Setup', 'Production', 'Optimization'];
  let currentDate = new Date();
  const sortedTasks = [...tasks].sort((a, b) => phases.indexOf(a.phase) - phases.indexOf(b.phase));
  return sortedTasks.map(task => {
    while (currentDate.getDay() === 0 || currentDate.getDay() === 6) currentDate.setDate(currentDate.getDate() + 1);
    const dueDate = currentDate.toISOString().split('T')[0];
    currentDate.setDate(currentDate.getDate() + Math.ceil(task.estimated_hours / 6));
    return { ...task, due_date: dueDate, status: 'todo' };
  });
}

const context = $input.first().json;
const { scope, project_name, deadline, context_data } = context.genesis_data;

let baseTasks = TASK_TEMPLATES[scope] || [];
if (scope === 'full_scale') baseTasks = [...TASK_TEMPLATES.meta_ads, ...TASK_TEMPLATES.seo, ...TASK_TEMPLATES.sem, ...TASK_TEMPLATES.analytics];

const tasksWithDates = calculateDueDates(baseTasks, deadline);
const totalHours = tasksWithDates.reduce((sum, t) => sum + t.estimated_hours, 0);

return [{
  json: {
    action: 'genesis_complete',
    project: { name: project_name, scope, status: 'planning', current_phase: 'Audit', state_flags: { strategy_validated: false, budget_approved: false, creatives_ready: false, tracking_ready: false, ads_live: false }, metadata: context_data || {} },
    tasks: tasksWithDates,
    chat_message: `**Projet créé!** ${tasksWithDates.length} tâches générées pour **${project_name}** (${totalHours}h estimées).`,
    meta: { agent_id: 'pm', action: 'genesis', tasks_count: tasksWithDates.length }
  }
}];

// TASK LAUNCH HANDLER - Prepare for Memory Read
const context = $input.first().json;
const taskData = context.task_data;

return [{
  json: {
    ...context,
    project_id_for_memory: taskData.project_id,
    active_agent_id: taskData.active_agent_id,
    user_message: taskData.user_message,
    shared_memory: taskData.shared_memory,
    task_context: taskData.task_context
  }
}];

// ============================================================================
// BUILD MEMORY CONTEXT V4.4
// ============================================================================

const originalContext = $('Task Launch Handler').first().json;
const memoryRecords = $input.all().map(item => item.json) || [];

const previousWork = memoryRecords.map(record => ({
  agent: record.agent_id,
  what_was_done: record.summary,
  key_findings: record.key_findings || [],
  deliverables: record.deliverables || [],
  recommendations: record.recommendations || [],
  timestamp: record.created_at
}));

function extractRelevantRecommendations(previousWork, currentAgent) {
  const recommendations = [];
  for (const work of previousWork) {
    if (work.recommendations && work.recommendations.length > 0) {
      const agentRecos = work.recommendations.filter(r => 
        typeof r === 'string' && r.toLowerCase().includes(currentAgent.toLowerCase())
      );
      if (agentRecos.length > 0) {
        recommendations.push({ from_agent: work.agent, recommendations: agentRecos.slice(0, 3) });
      }
    }
  }
  return recommendations.slice(0, 5);
}

const memoryContext = {
  project_summary: originalContext.shared_memory?.project_name || 'Projet en cours',
  previous_work: previousWork,
  validated_elements: {
    usp: originalContext.shared_memory?.metadata?.usp || null,
    persona: originalContext.shared_memory?.metadata?.targetPersona || null,
    competitors: originalContext.shared_memory?.metadata?.competitors || [],
    tone: originalContext.shared_memory?.metadata?.editorial_tone || 'professional'
  },
  current_state: {
    phase: originalContext.shared_memory?.current_phase || 'setup',
    flags: originalContext.shared_memory?.state_flags || {}
  },
  recommendations_for_current_task: extractRelevantRecommendations(previousWork, originalContext.active_agent_id)
};

return [{
  json: {
    user_message: originalContext.user_message,
    session_id: originalContext.session_id,
    suggested_agent_id: originalContext.active_agent_id,
    shared_memory: originalContext.shared_memory,
    task_context: originalContext.task_context,
    memory_context: memoryContext,
    previous_work_summary: previousWork.map(w => `${w.agent}: ${w.what_was_done}`).join('\n'),
    project_id: originalContext.project_id_for_memory
  }
}];

// ============================================================================
// PHASE 0 - DETECT AGENT ACTION
// ============================================================================
// Analyse le message utilisateur + agent actif pour détecter quelle action
// critique est sur le point d'être exécutée

const context = $input.first().json;
const userMessage = (context.user_message || '').toLowerCase();
const agentId = context.suggested_agent_id;

// Map agent_id vers type agent
const agentTypeMap = {
  'marcus': 'trader',
  'milo': 'creative',
  'sora': 'analyst',
  'luna': 'strategist'
};

const agentType = agentTypeMap[agentId] || null;

// Détection d'action par patterns de mots-clés
let detectedAction = null;

if (agentType === 'trader') {
  if (userMessage.includes('lance') || userMessage.includes('lancer') || userMessage.includes('campagne')) {
    detectedAction = 'launch_campaign';
  } else if (userMessage.includes('scale') || userMessage.includes('augment')) {
    detectedAction = 'scale_campaign';
  } else if (userMessage.includes('stop') || userMessage.includes('arrête') || userMessage.includes('kill')) {
    detectedAction = 'kill_campaign';
  } else if (userMessage.includes('budget') && (userMessage.includes('modif') || userMessage.includes('change'))) {
    detectedAction = 'update_budget';
  }
} else if (agentType === 'creative') {
  if (userMessage.includes('génère') || userMessage.includes('crée') || userMessage.includes('final')) {
    detectedAction = 'generate_final_creatives';
  } else if (userMessage.includes('vidéo') || userMessage.includes('video')) {
    detectedAction = 'generate_video';
  } else if (userMessage.includes('brand') || userMessage.includes('marque')) {
    detectedAction = 'generate_brand_assets';
  }
} else if (agentType === 'analyst') {
  if (userMessage.includes('dashboard')) {
    detectedAction = 'create_dashboard';
  } else if (userMessage.includes('analys') || userMessage.includes('performance')) {
    detectedAction = 'analyze_campaign_performance';
  } else if (userMessage.includes('audit') && userMessage.includes('tracking')) {
    detectedAction = 'audit_tracking';
  } else if (userMessage.includes('rapport') || userMessage.includes('report')) {
    detectedAction = 'generate_report';
  }
} else if (agentType === 'strategist') {
  if (userMessage.includes('finalise') || userMessage.includes('valide') && userMessage.includes('stratég')) {
    detectedAction = 'finalize_strategy';
  } else if (userMessage.includes('concurrent') || userMessage.includes('compet')) {
    detectedAction = 'competitive_analysis';
  } else if (userMessage.includes('positionnement')) {
    detectedAction = 'validate_positioning';
  }
}

return [{
  json: {
    ...context,
    agent_type: agentType,
    detected_action: detectedAction,
    requires_validation: detectedAction !== null
  }
}];

// ============================================================================
// PHASE 0 - VALIDATE STATE FLAGS
// ============================================================================
// Implémentation inline de validateStateBeforeAction()

const STATE_VALIDATION_RULES = {
  trader: {
    launch_campaign: {
      required_flags: ['strategy_validated', 'budget_approved', 'creatives_ready', 'tracking_ready'],
      required_phase: ['Production', 'Optimization'],
      error_message: "Impossible de lancer la campagne: validations manquantes",
      help_text: "Complétez d'abord: Stratégie (Luna) → Budget (Approval) → Assets (Milo) → Tracking (Sora)",
      severity: 'blocking'
    },
    scale_campaign: {
      required_flags: ['ads_live'],
      minimum_runtime_hours: 48,
      error_message: "Impossible de scaler: campagne trop récente (attendez fin Learning Phase)",
      help_text: "Meta Ads nécessite 48h minimum de Learning Phase avant scaling",
      severity: 'blocking'
    },
    kill_campaign: {
      required_flags: ['ads_live'],
      error_message: "Aucune campagne active à arrêter",
      help_text: "Il n'y a actuellement aucune campagne en cours d'exécution",
      severity: 'warning'
    },
    update_budget: {
      required_flags: ['ads_live'],
      error_message: "Impossible de modifier le budget: aucune campagne active",
      severity: 'blocking'
    }
  },
  creative: {
    generate_final_creatives: {
      required_flags: ['strategy_validated'],
      required_phase: ['Production', 'Optimization'],
      error_message: "Attendez validation de la stratégie avant génération finale",
      help_text: "Luna doit d'abord valider le positionnement et le ton de marque",
      severity: 'blocking'
    },
    generate_video: {
      required_flags: ['strategy_validated'],
      cost_approval_threshold: 50,
      error_message: "Génération vidéo nécessite validation stratégie + approbation coût",
      help_text: "Les vidéos sont coûteuses. Assurez-vous que la stratégie est validée.",
      severity: 'warning'
    },
    generate_brand_assets: {
      required_flags: ['strategy_validated'],
      error_message: "Validez d'abord l'identité de marque avec Luna",
      help_text: "Les assets de marque doivent respecter le positionnement validé",
      severity: 'blocking'
    }
  },
  analyst: {
    create_dashboard: {
      required_flags: ['tracking_ready'],
      error_message: "Tracking non configuré: données indisponibles",
      help_text: "Installez d'abord le pixel Meta ou le tag GA4 pour collecter des données",
      severity: 'blocking'
    },
    analyze_campaign_performance: {
      required_flags: ['ads_live'],
      minimum_runtime_hours: 24,
      error_message: "Campagne trop récente pour une analyse fiable",
      help_text: "Attendez au minimum 24h de données avant analyse",
      severity: 'warning'
    },
    audit_tracking: {
      required_phase: ['Setup', 'Production'],
      error_message: "L'audit tracking doit être fait en phase Setup ou Production",
      severity: 'warning'
    },
    generate_report: {
      required_flags: ['tracking_ready'],
      minimum_runtime_hours: 24,
      error_message: "Données insuffisantes pour générer un rapport",
      help_text: "Attendez au moins 24h de collecte de données",
      severity: 'warning'
    }
  },
  strategist: {
    finalize_strategy: {
      required_phase: ['Audit', 'Setup'],
      error_message: "Finalisez d'abord l'audit avant de valider la stratégie",
      help_text: "Phase Audit doit être complétée pour avoir toutes les données",
      severity: 'blocking'
    },
    competitive_analysis: {
      required_phase: ['Audit'],
      error_message: "L'analyse concurrentielle se fait en phase Audit",
      severity: 'warning'
    },
    validate_positioning: {
      required_phase: ['Audit', 'Setup'],
      error_message: "Le positionnement se valide après l'audit",
      severity: 'blocking'
    }
  }
};

const FLAG_DESCRIPTIONS = {
  strategy_validated: { label: "Stratégie validée", responsible_agent: "luna", icon: "target" },
  budget_approved: { label: "Budget approuvé", responsible_agent: "user", icon: "dollar-sign" },
  creatives_ready: { label: "Assets créatifs prêts", responsible_agent: "creative", icon: "image" },
  tracking_ready: { label: "Tracking configuré", responsible_agent: "analyst", icon: "activity" },
  ads_live: { label: "Campagne active", responsible_agent: "trader", icon: "play-circle" }
};

const context = $('Detect Agent Action').first().json;
const projectState = $input.first().json;

const agentType = context.agent_type;
const action = context.detected_action;

const rules = STATE_VALIDATION_RULES[agentType]?.[action];

if (!rules) {
  // Pas de règle = validation OK
  return [{ json: { ...context, validation_passed: true, validation_result: { valid: true } } }];
}

const project = projectState;

// ─────────────────────────────────────────────────────────────────────────
// 2. Vérifier les flags requis
// ─────────────────────────────────────────────────────────────────────────
if (rules.required_flags && rules.required_flags.length > 0) {
  const missingFlags = rules.required_flags.filter(
    flag => !project.state_flags?.[flag]
  );

  if (missingFlags.length > 0) {
    return [{
      json: {
        ...context,
        validation_passed: false,
        validation_result: {
          valid: false,
          error: rules.error_message,
          missing_flags: missingFlags.map(flag => ({
            flag: flag,
            ...FLAG_DESCRIPTIONS[flag]
          })),
          resolution: rules.help_text,
          severity: rules.severity || 'blocking',
          validation_type: 'missing_flags'
        }
      }
    }];
  }
}

// ─────────────────────────────────────────────────────────────────────────
// 3. Vérifier la phase requise
// ─────────────────────────────────────────────────────────────────────────
if (rules.required_phase && rules.required_phase.length > 0) {
  if (!rules.required_phase.includes(project.current_phase)) {
    return [{
      json: {
        ...context,
        validation_passed: false,
        validation_result: {
          valid: false,
          error: `Action autorisée seulement en phase: ${rules.required_phase.join(' ou ')}`,
          current_phase: project.current_phase,
          required_phases: rules.required_phase,
          resolution: `Passez d'abord à la phase ${rules.required_phase[0]}`,
          severity: rules.severity || 'blocking',
          validation_type: 'wrong_phase'
        }
      }
    }];
  }
}

// ─────────────────────────────────────────────────────────────────────────
// 4. Vérifier le runtime minimum (pour scale, analyze, etc.)
// ─────────────────────────────────────────────────────────────────────────
if (rules.minimum_runtime_hours) {
  const campaign = project.metadata?.campaign;

  if (!campaign?.launched_at) {
    return [{
      json: {
        ...context,
        validation_passed: false,
        validation_result: {
          valid: false,
          error: "Aucune campagne active trouvée",
          resolution: "Lancez d'abord une campagne avec Marcus",
          severity: rules.severity || 'blocking',
          validation_type: 'no_campaign'
        }
      }
    }];
  }

  const hoursSinceLaunch =
    (Date.now() - new Date(campaign.launched_at).getTime()) / 3600000;

  if (hoursSinceLaunch < rules.minimum_runtime_hours) {
    const hoursRemaining = Math.ceil(rules.minimum_runtime_hours - hoursSinceLaunch);

    return [{
      json: {
        ...context,
        validation_passed: false,
        validation_result: {
          valid: false,
          error: rules.error_message,
          hours_remaining: hoursRemaining,
          hours_since_launch: Math.floor(hoursSinceLaunch),
          minimum_hours: rules.minimum_runtime_hours,
          resolution: rules.help_text,
          severity: rules.severity || 'warning',
          validation_type: 'insufficient_runtime'
        }
      }
    }];
  }
}

// ✅ Toutes les validations passées
return [{
  json: {
    ...context,
    validation_passed: true,
    validation_result: {
      valid: true,
      message: `Validation OK pour ${agentType}.${action}`
    }
  }
}];

// ============================================================================
// PHASE 0 - FORMAT BLOCKED ERROR
// ============================================================================

const context = $input.first().json;
const validationResult = context.validation_result;

let errorMessage = `❌ **Action bloquée**: ${validationResult.error}\n\n`;

if (validationResult.validation_type === 'missing_flags') {
  errorMessage += `**Flags manquants:**\n`;
  for (const flag of validationResult.missing_flags) {
    errorMessage += `- ${flag.label} (${flag.icon}) - Responsable: ${flag.responsible_agent}\n`;
  }
  errorMessage += `\n**Résolution:** ${validationResult.resolution}`;
} else if (validationResult.validation_type === 'wrong_phase') {
  errorMessage += `**Phase actuelle:** ${validationResult.current_phase}\n`;
  errorMessage += `**Phases requises:** ${validationResult.required_phases.join(', ')}\n\n`;
  errorMessage += `**Résolution:** ${validationResult.resolution}`;
} else if (validationResult.validation_type === 'insufficient_runtime') {
  errorMessage += `**Heures écoulées:** ${validationResult.hours_since_launch}h\n`;
  errorMessage += `**Minimum requis:** ${validationResult.minimum_hours}h\n`;
  errorMessage += `**Temps restant:** ${validationResult.hours_remaining}h\n\n`;
  errorMessage += `**Résolution:** ${validationResult.resolution}`;
} else {
  errorMessage += `**Résolution:** ${validationResult.resolution || 'Contactez support'}`;
}

return [{
  json: {
    success: true,
    action: 'action_blocked',
    chat_message: errorMessage,
    ui_components: [{
      type: 'ERROR_BLOCKED_ACTION',
      data: validationResult
    }],
    meta: {
      agent_id: 'pm',
      action: 'validation_blocked',
      blocked_action: context.detected_action,
      blocked_agent: context.agent_type,
      severity: validationResult.severity,
      timestamp: new Date().toISOString()
    }
  }
}];

// ============================================================================
// PARSE PM AI RESPONSE & BUILD ORCHESTRATOR PAYLOAD
// ============================================================================

const originalContext = $('Detect Agent Action').first().json;
const aiResponse = $input.first().json;

// Parse AI response
let pmDecision = {};
try {
  const output = aiResponse.output || aiResponse.text || JSON.stringify(aiResponse);
  const jsonMatch = output.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    pmDecision = JSON.parse(jsonMatch[0]);
  }
} catch (e) {
  pmDecision = {
    selected_agent: originalContext.suggested_agent_id || 'orchestrator',
    routing_reason: 'Fallback to suggested agent',
    context_enrichment: '',
    coherence_notes: ''
  };
}

// Build memory injection for orchestrator
const memoryInjection = originalContext.memory_context.previous_work.length > 0 ? `

## CONTEXTE PROJET (MEMOIRE COLLECTIVE)

**Projet:** ${originalContext.memory_context.project_summary}
**Phase:** ${originalContext.memory_context.current_state.phase}

### Travaux précédents:
${originalContext.memory_context.previous_work.map(w => `- **${w.agent.toUpperCase()}:** ${w.what_was_done}`).join('\n')}

### Recommandations PM:
${pmDecision.context_enrichment || 'Aucune instruction supplémentaire.'}

### Cohérence à respecter:
${pmDecision.coherence_notes || 'Aucune contrainte spécifique.'}

### Eléments validés:
- USP: ${originalContext.memory_context.validated_elements.usp || 'Non définie'}
- Persona: ${originalContext.memory_context.validated_elements.persona || 'Non défini'}
- Ton: ${originalContext.memory_context.validated_elements.tone || 'Professionnel'}
` : '';

// Build orchestrator payload
const orchestratorPayload = {
  chatInput: originalContext.user_message,
  session_id: originalContext.session_id,
  activeAgentId: pmDecision.selected_agent || originalContext.suggested_agent_id,
  shared_memory: originalContext.shared_memory,
  task_context: originalContext.task_context,
  system_instruction: memoryInjection,
  memory_context: originalContext.memory_context,
  pm_decision: pmDecision
};

return [{ json: orchestratorPayload }];

// ============================================================================
// PROCESS ORCHESTRATOR RESPONSE V4.4
// ============================================================================

const originalContext = $('Parse PM Decision').first().json;
const orchestratorResponse = $input.first().json;

const memoryContribution = orchestratorResponse.memory_contribution || null;

const writeBackData = memoryContribution ? {
  project_id: originalContext.shared_memory?.project_id,
  agent_id: orchestratorResponse.meta?.agent_id || originalContext.activeAgentId,
  task_id: originalContext.task_context?.task_id || null,
  action: memoryContribution.action || 'TASK_COMPLETED',
  summary: memoryContribution.summary || (orchestratorResponse.chat_message || '').substring(0, 200),
  key_findings: memoryContribution.key_findings || [],
  deliverables: memoryContribution.deliverables || [],
  recommendations: memoryContribution.recommendations_for_next_agent || []
} : null;

const flagsToUpdate = memoryContribution?.flags_to_update || null;

return [{
  json: {
    chat_message: orchestratorResponse.chat_message,
    ui_components: orchestratorResponse.ui_components || [],
    meta: orchestratorResponse.meta,
    write_back_data: writeBackData,
    flags_to_update: flagsToUpdate,
    has_memory_contribution: writeBackData !== null,
    project_id: originalContext.shared_memory?.project_id,
    task_id: originalContext.task_context?.task_id,
    pm_decision: originalContext.pm_decision
  }
}];

const processedResponse = $('Process Response').first().json;
const memoryWriteResult = $('Write Memory').first()?.json || null;
return [{ json: { ...processedResponse, memory_written: memoryWriteResult !== null, memory_id: memoryWriteResult?.id || null } }];

// WRITE-BACK HANDLER
const context = $input.first().json;
const { task_id, project_id, updates, deliverable_url, state_flags } = context.writeback_data;

return [{
  json: {
    action: 'write_back_complete',
    result: { success: true, task_id, project_id, updates_applied: { task_status: updates?.status || 'done', deliverable_url, state_flags_updated: state_flags || {}, completed_at: new Date().toISOString() } },
    chat_message: '**Tâche mise à jour!** Livrable enregistré.',
    meta: { agent_id: 'pm', action: 'write_back', task_id }
  }
}];

// QUICK ACTION HANDLER - Prepare for memory read
const context = $input.first().json;
const chatData = context.chat_data;

return [{
  json: {
    ...context,
    project_id_for_memory: chatData.project_id,
    active_agent_id: chatData.active_agent_id,
    user_message: chatData.message,
    shared_memory: chatData.shared_memory,
    task_context: chatData.task_context,
    image: chatData.image
  }
}];

// NO VALIDATION NEEDED - Continue to PM AI Brain
const context = $input.first().json;
return [{ json: context }];

// ============================================================================
// FORMAT FINAL RESPONSE V4.4
// ============================================================================

const input = $input.first().json;

const finalResponse = {
  success: true,
  action: input.action || 'task_response',
  chat_message: input.chat_message || 'Demande traitée.',
  ui_components: input.ui_components || [],
  project: input.project || null,
  tasks: input.tasks || null,
  write_back_result: input.result || null,
  memory_updated: input.memory_written || input.has_memory_contribution || false,
  write_back: input.flags_to_update ? [{ type: 'UPDATE_STATE_FLAGS', flags: input.flags_to_update }] : [],
  meta: {
    ...input.meta,
    pm_version: 'v4.4-phase0-validated',
    pm_decision: input.pm_decision || null,
    timestamp: new Date().toISOString()
  }
};

return [{ json: finalResponse }];
